import { useMemo, useState } from "react";
import { categories, products } from "../data/products";
import ProductCard from "../components/products/ProductCard";
import FilterBar from "../components/products/FilterBar";

export default function ShopPage({ onAdd }) {
  const [activeCategory, setActiveCategory] = useState("All");

  const filteredProducts = useMemo(() => {
    if (activeCategory === "All") return products;
    return products.filter((product) => product.category === activeCategory);
  }, [activeCategory]);

  return (
    <section className="mx-auto max-w-7xl px-4 py-12 sm:px-6 lg:px-8">
      <div className="mb-8 flex flex-col gap-4 rounded-[2rem] border border-black/10 bg-white/70 p-6 shadow-soft backdrop-blur lg:flex-row lg:items-end lg:justify-between">
        <div className="max-w-2xl">
          <p className="text-xs font-semibold uppercase tracking-[0.3em] text-forest">Shop</p>
          <h1 className="mt-2 font-display text-4xl font-bold tracking-[-0.04em] text-ink sm:text-5xl">
            All pieces are made in limited runs.
          </h1>
          <p className="mt-4 text-base leading-8 text-ink/65">
            Once a drop sells through, we move on. That keeps the collection sharp and the inventory honest.
          </p>
        </div>

        <div className="grid gap-3 sm:grid-cols-3 lg:min-w-[24rem]">
          {[
            ["8", "pieces live"],
            ["4", "categories"],
            ["1", "story-first brand"],
          ].map(([value, label]) => (
            <div key={label} className="rounded-[1.4rem] border border-black/10 bg-paper/80 p-4 text-center">
              <p className="font-display text-2xl font-bold text-forest">{value}</p>
              <p className="mt-1 text-[11px] uppercase tracking-[0.22em] text-ink/45">{label}</p>
            </div>
          ))}
        </div>
      </div>

      <FilterBar categories={categories} activeCategory={activeCategory} onSelect={setActiveCategory} />

      <div className="mt-8 grid gap-5 md:grid-cols-2 xl:grid-cols-3">
        {filteredProducts.map((product) => (
          <ProductCard key={product.id} product={product} onAdd={onAdd} />
        ))}
      </div>
    </section>
  );
}
